// Parse JSON output จาก Gemini
try {
  let raw = $input.item.json.text || $input.item.json.output || '';
  // ลบ markdown code block ออก
  raw = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
  const parsed = JSON.parse(raw);
  return { json: parsed };
} catch (e) {
  return {
    json: {
      action: 'reply',
      message: 'ขออภัยครับ ผมไม่สามารถประมวลผลคำสั่งได้ในตอนนี้ กรุณาลองใหม่อีกครั้ง',
      data: null
    }
  };
}

// สร้าง Response สำหรับ Quotation
// ส่งข้อมูลกลับตรงๆ ไปหน้าเว็บได้เลย
const payload = $input.item.json;
return {
  json: {
    action: 'quotation',
    message: payload.message || 'ร่างใบเสนอราคาให้คุณเรียบร้อยแล้วครับ ✅',
    data: payload.data || {}
  }
};

// ตัดสต็อก — อ่านค่าเดิม แล้วลบออก
// หมายเหตุ: ในงานจริงต้องอ่านค่าปัจจุบันก่อน แล้วค่อยคำนวณ
// นี่เป็น Logic ตัวอย่าง สามารถปรับให้ Read ก่อน Update ได้
const productName = $json.data.productName;
const amount = $json.data.amount;
return {
  json: {
    ...$json,
    deductInfo: {
      productName,
      amount,
      note: `ตัดสต็อก ${amount} ${$json.data.unit || 'ชิ้น'} เมื่อ ${new Date().toLocaleString('th-TH')}`
    }
  }
};

// รวม response จากทุก branch กลับมาเป็น format เดียวกัน
// และส่งกลับไปหน้าเว็บ React
const input = $input.item.json;

// ถ้ามาจาก Google Sheets node จะมี updatedRows หรือ appendedRow
const originalAction = input.action || 'database';
const originalMsg = input.message || 'ดำเนินการเรียบร้อยแล้วครับ ✅';

return {
  json: {
    action: originalAction,
    message: originalMsg,
    data: input.data || null
  }
};

// ตอบกลับข้อความทั่วไป
return {
  json: {
    action: 'reply',
    message: $input.item.json.message || 'มีอะไรให้ผมช่วยไหมครับ?',
    data: null
  }
};
